  getFormatDateGlobal(date) {
    if (!date)
      return "";
    if (typeof date === "object" && !(date instanceof Date))
      return "";
    if (typeof date === "string") {
      const str = date.trim();
      if (/^\d{2}\/\d{2}\/\d{4}$/.test(str)) {
        const [day, month, year] = str.split("/");
        const parsed = new Date(+year, +month - 1, +day);
        if (!isNaN(parsed.getTime()))
          date = parsed;
        else
          return "";
      } else if (/^\d{2}-\d{2}-\d{4}$/.test(str)) {
        const [day, month, year] = str.split("-");
        const parsed = new Date(+year, +month - 1, +day);
        if (!isNaN(parsed.getTime()))
          date = parsed;
        else
          return "";
      } else if (/^\d{2}-[A-Za-z]{3}-\d{4}$/.test(str)) {
        const parsed = new Date(str);
        if (!isNaN(parsed.getTime()))
          date = parsed;
        else
          return "";
      } else {
        const parsed = new Date(str);
        if (!isNaN(parsed.getTime()))
          date = parsed;
        else
          return "";
      }
    }
    const storedFormat = sessionStorage.getItem("dateformat") ?? "";
    let format = "dd/MM/yyyy";
    switch (storedFormat) {
      case "MM DD YYYY":
        format = "MM dd yyyy";
        break;
      case "DD MM YYYY":
        format = "dd MM yyyy";
        break;
      case "YYYY MM DD":
        format = "yyyy MM dd";
        break;
      case "DD/MM/YYYY":
        format = "dd/MM/yyyy";
        break;
      case "MM/DD/YYYY":
        format = "MM/dd/yyyy";
        break;
      case "YYYY/MM/DD":
        format = "yyyy/MM/dd";
        break;
      case "DD-MM-YYYY":
        format = "dd-MM-yyyy";
        break;
      case "MM-DD-YYYY":
        format = "MM-dd-yyyy";
        break;
      case "YYYY-MM-DD":
        format = "yyyy-MM-dd";
        break;
      case "DD-MMM-YYYY":
        format = "dd-MMM-yyyy";
        break;
      case "MMM-DD-YYYY":
        format = "MMM-dd-yyyy";
        break;
      case "YYYY-MMM-DD":
        format = "yyyy-MMM-dd";
        break;
      case "YYYY-DD-MMM":
        format = "dd-MMM-yyyy";
        break;
    }
    return this.datepipe.transform(date, format) ?? "";
  }
