  getDateObjectFromDataBase(date) {
    if (!date)
      return null;
    try {
      if (date instanceof Date) {
        return date;
      }
      if (typeof date === "string") {
        return new Date(date);
      }
      if (typeof date === "number") {
        return new Date(date);
      }
      return null;
    } catch (error) {
      console.error("Invalid date received from DB:", date);
      return null;
    }
  }
