  _MultipleGroupingGridExportData(gridData, groupedCol, isGroupedColDate) {
    const groupedByCol = {};
    const groupedByTransaction = {};
    const groupKeys = [];
    const transactionKeys = [];
    const finalList = [];
    for (const row of gridData) {
      const groupColValue = isGroupedColDate ? this.getFormatDateGlobal(row[groupedCol]) : row[groupedCol];
      const transactionNo = row["ptransactionno"];
      if (!groupedByCol[groupColValue]) {
        groupedByCol[groupColValue] = [__spreadValues({}, row)];
        groupKeys.push(groupColValue);
      } else {
        groupedByCol[groupColValue].push(row);
      }
      if (!groupedByTransaction[transactionNo]) {
        groupedByTransaction[transactionNo] = [__spreadValues({}, row)];
        transactionKeys.push(transactionNo);
      } else {
        groupedByTransaction[transactionNo].push(row);
      }
    }
    for (const txKey of transactionKeys) {
      const transactionRows = groupedByTransaction[txKey];
      transactionRows.forEach((row, idx) => {
        if (idx === 0) {
          row["group"] = {
            content: `               ${row["ptransactionno"]}`,
            colSpan: 15,
            styles: { halign: "left", fontStyle: "bold", textColor: "#663300" }
          };
        }
        finalList.push(row);
      });
    }
    const newDataArray = [];
    for (const key of groupKeys) {
      newDataArray.push({
        group: {
          content: `${key}`,
          colSpan: 15,
          styles: { halign: "left", fontStyle: "bold", textColor: "#009933" }
        }
      });
      for (const row of finalList) {
        const rowGroupValue = isGroupedColDate ? this.getFormatDateGlobal(row[groupedCol]) : row[groupedCol];
        if (rowGroupValue === key) {
          newDataArray.push(row);
        }
      }
    }
    return newDataArray;
  }
