  _downloadChequesOnHandReportsPdf(reportName, gridData, gridHeaders, colWidthHeight, pageType, betweenOrAsOn, fromDate, toDate2, printOrPdf, chequesAmt) {
    const companyDetails = this._getCompanyDetails();
    const address = this.getcompanyaddress();
    const companyName = companyDetails?.companyName ?? "";
    const companyAddress = companyDetails?.registrationAddress ?? "";
    const companyCIN = companyDetails?.cinNumber ?? "";
    const companyBranch = companyDetails?.branchName ?? "";
    const doc = new E3({ orientation: pageType });
    const totalPagesExp = "{total_pages_count_string}";
    const today = this.pdfProperties("Date");
    const kapilLogo = this.getKapilGroupLogo();
    const currencyFormat = this.currencysymbol;
    const rupeeImage = this._getRupeeSymbol();
    const lMargin = 10;
    const rMargin = 10;
    let pageHeight = 0;
    (0, import_jspdf_autotable.default)(doc, {
      head: [gridHeaders],
      body: gridData,
      theme: "grid",
      startY: 48,
      styles: {
        fontSize: Number(this.pdfProperties("Cell Fontsize")),
        cellPadding: 1,
        overflow: "linebreak"
      },
      headStyles: {
        fillColor: this.pdfProperties("Header Color"),
        halign: this.pdfProperties("Header Alignment"),
        fontSize: Number(this.pdfProperties("Header Fontsize"))
      },
      columnStyles: colWidthHeight,
      didDrawPage: (data) => {
        const pageSize2 = doc.internal.pageSize;
        const pageWidth2 = pageSize2.getWidth();
        pageHeight = pageSize2.getHeight();
        doc.setFont("helvetica", "normal");
        doc.setFontSize(15);
        if (doc.getNumberOfPages() === 1) {
          doc.addImage(kapilLogo, "JPEG", 10, 5, 20, 20);
          doc.text(companyDetails?.companyName ?? "", pageWidth2 / 2, 10, { align: "center" });
          doc.setFontSize(10);
          doc.text(address, pageWidth2 / 2, 15, { align: "center" });
          if (companyDetails?.cinNumber ?? "") {
            doc.text(`CIN : ${companyDetails?.cinNumber}`, pageWidth2 / 2, 20, { align: "center" });
          }
          doc.setFontSize(14);
          doc.text(reportName, pageWidth2 / 2, 30, { align: "center" });
          doc.setFontSize(10);
          doc.text(`Branch : ${companyDetails?.branchName}`, pageWidth2 - rMargin, 40, { align: "right" });
          if (betweenOrAsOn === "Between") {
            doc.text(`Between : ${fromDate} And ${toDate2}`, lMargin, 40);
          } else {
            doc.text(`As On : ${fromDate}`, lMargin, 40);
          }
          doc.line(lMargin, 45, pageWidth2 - rMargin, 45);
        }
        let pageText = `Page ${doc.getNumberOfPages()}`;
        if (typeof doc.putTotalPages === "function") {
          pageText += ` of ${totalPagesExp}`;
        }
        doc.line(lMargin, pageHeight - 10, pageWidth2 - rMargin, pageHeight - 10);
        doc.setFontSize(10);
        doc.text(`Printed on : ${today}`, data.settings.margin.left, pageHeight - 5);
        doc.text(pageText, pageWidth2 - 35, pageHeight - 5);
      },
      didDrawCell: (data) => {
        if ((data.column.index === 3 || data.column.index === 6) && data.section === "body") {
          if (currencyFormat === "\u20B9") {
            const x4 = data.cell.x + 1;
            const y5 = data.cell.y + data.cell.height / 2;
            doc.addImage(rupeeImage, "JPEG", x4, y5 - 1, 1.5, 1.5);
          }
        }
      }
    });
    const finalY = doc.lastAutoTable.finalY;
    const pageSize = doc.internal.pageSize;
    const pageWidth = pageSize.getWidth();
    doc.setFontSize(10);
    if (finalY + 80 < pageHeight - 20) {
      doc.text("Cheques Total : ", pageWidth - 70, finalY + 10);
      if (currencyFormat === "\u20B9") {
        doc.addImage(rupeeImage, "JPEG", pageWidth - 42, finalY + 8.5, 1.5, 1.5);
      }
      doc.text(chequesAmt, pageWidth - 40, finalY + 10);
      doc.text("Accounts Officer", 25, finalY + 100);
      doc.text("Verified By", pageWidth - 60, finalY + 100);
    } else {
      doc.addPage();
      doc.text("Cheques Total : ", pageWidth - 70, 10);
      if (currencyFormat === "\u20B9") {
        doc.addImage(rupeeImage, "JPEG", pageWidth - 42, 8.5, 1.5, 1.5);
      }
      doc.text(chequesAmt, pageWidth - 40, 10);
      doc.text("Accounts Officer", 25, 100);
      doc.text("Verified By", pageWidth - 60, 100);
    }
    if (typeof doc.putTotalPages === "function") {
      doc.putTotalPages(totalPagesExp);
    }
    if (printOrPdf === "Pdf") {
      doc.save(`${reportName}.pdf`);
    }
    if (printOrPdf === "Print") {
      this.setiFrameForPrint(doc);
    }
  }
  transform(items, searchText, columnName) {
    debugger;
    if (!items)
      return [];
    if (!searchText)
      return items;
    searchText = searchText.toString().toLowerCase();
    return items.filter((it2) => {
      return it2[columnName].toString().toLowerCase().startsWith(searchText);
    });
  }
