  getFormatDate1(date) {
    if (!date)
      return null;
    const dateFormat = sessionStorage.getItem("dateformat");
    if (dateFormat === "DD-MMM-YYYY") {
      return this.datepipe.transform(date, "dd-MM-yyyy");
    }
    return this.datepipe.transform(date, "yyyy-MM-dd");
  }
