  _groupwiseSummaryExportDataTB(griddata, groupdcol, debitamount1, creditamount1, debitamount2, creditamount2, debittotal, credittotal, sumstring, isgroupedcolDate) {
    const groupMap = /* @__PURE__ */ new Map();
    for (const row of griddata) {
      const groupKey = isgroupedcolDate ? this.getFormatDateGlobal(row[groupdcol]) : String(row[groupdcol] ?? "");
      if (!groupMap.has(groupKey)) {
        groupMap.set(groupKey, []);
      }
      groupMap.get(groupKey).push(row);
    }
    const final = [];
    for (const [groupKey, rows] of groupMap.entries()) {
      final.push({
        isGroupHeader: true,
        groupLabel: groupKey,
        group: {
          content: groupKey,
          colSpan: 7,
          styles: {
            halign: "left",
            fillColor: "#e6f7ff",
            fontStyle: "bold",
            fontSize: 9
          }
        }
      });
      let d1Sum = 0, c1Sum = 0, d2Sum = 0, c2Sum = 0, dtSum = 0, ctSum = 0;
      for (const row of rows) {
        d1Sum += parseFloat(row[debitamount1]) || 0;
        c1Sum += parseFloat(row[creditamount1]) || 0;
        d2Sum += parseFloat(row[debitamount2]) || 0;
        c2Sum += parseFloat(row[creditamount2]) || 0;
        dtSum += parseFloat(row[debittotal]) || 0;
        ctSum += parseFloat(row[credittotal]) || 0;
        final.push(row);
      }
      final.push({
        isSubtotal: true,
        accountname: `${groupKey} Total`,
        [debitamount1]: d1Sum,
        [creditamount1]: c1Sum,
        [debitamount2]: d2Sum,
        [creditamount2]: c2Sum,
        [debittotal]: dtSum,
        [credittotal]: ctSum
      });
    }
    return final;
  }
